// src/components/About.jsx
import { personal } from '../data/portfolio';

// Cada card tiene su propio estilo visual distinto
const cards = [
  {
    icon: '⚛',
    title: 'Frontend dinámico y limpio',
    text: 'Mi objetivo es crear interfaces que el usuario disfrute usar. Con React como mi herramienta principal, me enfoco en construir componentes reutilizables y mantener un código ordenado.',
    style: 'border-left', // acento lateral
    accent: 'var(--accent)',
  },
  {
    icon: '⚙',
    title: 'Backend orientado a negocio',
    text: 'En mis prácticas con .NET me enfrenté a proyectos corporativos reales. Aprendí a trabajar con modelos de datos, entender la arquitectura del sistema y la lógica que hay detrás de la pantalla.',
    style: 'filled', // fondo con tono
    accent: 'rgba(232,58,58,0.08)',
  },
  {
    icon: '🗄',
    title: 'Bases de datos sólidas',
    text: 'Trabajar con SQL Server en un entorno de producción me enseñó a valorar el rendimiento. Entiendo la importancia de diseñar buenas consultas para que la aplicación fluya.',
    style: 'outlined', // borde más marcado
    accent: 'rgba(232,58,58,0.22)',
  },
  {
    icon: '💪',
    title: 'Ética de trabajo real',
    text: 'Compaginar el grado de DAW con mi trabajo en logística me ha dado una disciplina inquebrantable. Busco mi primera oportunidad como Junior, aportando la madurez y responsabilidad de un trabajador constante.',
    style: 'minimal', // sin borde, solo espaciado
    accent: 'var(--text3)',
  },
];

export default function About() {
  const { bio, contact } = personal;

  return (
    <section id="about" style={s.section}>
      <div style={s.inner}>
        <div className="reveal">
          <p style={s.label}>About me / Sobre mí</p>
          <h2 style={s.title}>Who I am</h2>
        </div>

        <div style={s.grid}>
          {/* Left: bio + info */}
          <div>
            {bio.map((p, i) => (
              <p key={i} className={`reveal reveal-delay-${i + 1}`} style={s.bioPara}>
                {p}
              </p>
            ))}

            <div className="reveal" style={s.infoList}>
              {[
                { label: 'Location', val: contact.location },
                { label: 'Email',    val: contact.email,      href: `mailto:${contact.email}` },
                { label: 'LinkedIn', val: 'rubén-marco',      href: contact.linkedin },
                { label: 'Portfolio',val: 'unsitiogenial.es', href: contact.portfolio },
                { label: 'Idiomas',  val: contact.languages },
                { label: 'Extras',   val: contact.extras },
              ].map((item) => (
                <div key={item.label} style={s.infoItem}>
                  <span style={s.infoLabel}>{item.label}</span>
                  {item.href ? (
                    <a href={item.href} target="_blank" rel="noreferrer" style={s.infoLink}>
                      {item.val}
                    </a>
                  ) : (
                    <span style={s.infoVal}>{item.val}</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right: cards con diseño distinto cada una */}
          <div style={s.cards}>
            {cards.map((c, i) => (
              <CardVariant key={c.title} card={c} index={i} />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

function CardVariant({ card, index }) {
  const { style, accent, icon, title, text } = card;

  if (style === 'border-left') {
    return (
      <div
        className={`reveal reveal-delay-1`}
        style={{
          ...s.cardBase,
          borderLeft: `3px solid ${accent}`,
          borderTop: '1px solid var(--border)',
          borderRight: '1px solid var(--border)',
          borderBottom: '1px solid var(--border)',
          borderRadius: '0 12px 12px 0',
          paddingLeft: 20,
        }}
        onMouseEnter={e => (e.currentTarget.style.background = 'rgba(232,58,58,0.04)')}
        onMouseLeave={e => (e.currentTarget.style.background = 'var(--card)')}
      >
        <span style={s.iconLarge}>{icon}</span>
        <div>
          <div style={{ ...s.cardTitle, color: 'var(--accent2)' }}>{title}</div>
          <div style={s.cardText}>{text}</div>
        </div>
      </div>
    );
  }

  if (style === 'filled') {
    return (
      <div
        className={`reveal reveal-delay-2`}
        style={{
          ...s.cardBase,
          background: accent,
          border: '1px solid rgba(232,58,58,0.18)',
          borderRadius: 12,
        }}
        onMouseEnter={e => (e.currentTarget.style.background = 'rgba(232,58,58,0.13)')}
        onMouseLeave={e => (e.currentTarget.style.background = accent)}
      >
        <span style={s.iconLarge}>{icon}</span>
        <div>
          <div style={s.cardTitle}>{title}</div>
          <div style={s.cardText}>{text}</div>
        </div>
      </div>
    );
  }

  if (style === 'outlined') {
    return (
      <div
        className={`reveal reveal-delay-3`}
        style={{
          ...s.cardBase,
          background: 'transparent',
          border: `1.5px solid ${accent}`,
          borderRadius: 12,
        }}
        onMouseEnter={e => (e.currentTarget.style.borderColor = 'var(--accent)')}
        onMouseLeave={e => (e.currentTarget.style.borderColor = accent)}
      >
        <span style={s.iconLarge}>{icon}</span>
        <div>
          <div style={s.cardTitle}>{title}</div>
          <div style={s.cardText}>{text}</div>
        </div>
      </div>
    );
  }

  // minimal — sin borde, separador sutil
  return (
    <div
      className={`reveal reveal-delay-4`}
      style={{
        ...s.cardBase,
        background: 'transparent',
        border: 'none',
        borderTop: `1px dashed rgba(255,255,255,0.08)`,
        borderRadius: 0,
        paddingTop: 20,
      }}
    >
      <span style={{ ...s.iconLarge, opacity: 0.7 }}>{icon}</span>
      <div>
        <div style={{ ...s.cardTitle, color: 'var(--text2)' }}>{title}</div>
        <div style={{ ...s.cardText, fontStyle: 'italic' }}>{text}</div>
      </div>
    </div>
  );
}

const s = {
  section:  { background: 'var(--bg2)', padding: '100px 5%' },
  inner:    { maxWidth: 1200, margin: '0 auto' },
  label:    { fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
  title:    { fontFamily: 'var(--font-head)', fontSize: 'clamp(30px, 5vw, 50px)', fontWeight: 800, letterSpacing: '-2px', color: 'var(--text)', marginBottom: 56 },
  grid:     { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 64, alignItems: 'start' },
  bioPara:  { fontSize: 15, color: 'var(--text2)', lineHeight: 1.82, marginBottom: 18, fontWeight: 300 },
  infoList: { display: 'flex', flexDirection: 'column', gap: 10, marginTop: 32, paddingTop: 28, borderTop: '1px solid var(--border)' },
  infoItem: { display: 'flex', gap: 14, alignItems: 'baseline' },
  infoLabel:{ fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text3)', minWidth: 76 },
  infoVal:  { fontSize: 14, color: 'var(--text)' },
  infoLink: { fontSize: 14, color: 'var(--accent2)', textDecoration: 'none' },
  cards:    { display: 'flex', flexDirection: 'column', gap: 12 },
  cardBase: {
    background: 'var(--card)',
    padding: '18px 22px',
    display: 'flex', alignItems: 'flex-start', gap: 16,
    transition: 'background 0.2s, border-color 0.2s',
    cursor: 'default',
  },
  iconLarge: { fontSize: 22, flexShrink: 0, marginTop: 2 },
  cardTitle: { fontFamily: 'var(--font-head)', fontSize: 14, fontWeight: 700, color: 'var(--text)', marginBottom: 5, lineHeight: 1.3 },
  cardText:  { fontSize: 13, color: 'var(--text2)', lineHeight: 1.65 },
};
